function SensorDashboard() {
  const [sensors, setSensors] = React.useState([
    { name: 'Living Room Temp', value: '72.4 °F', icon: '🌡️', status: 'normal', color: '#10b981' },
    { name: 'Bedroom Humidity', value: '48 %', icon: '💧', status: 'normal', color: '#3b82f6' },
    { name: 'Front Door', value: 'Closed', icon: '🚪', status: 'normal', color: '#10b981' },
    { name: 'Backyard Motion', value: 'Clear', icon: '🏃', status: 'normal', color: '#6b7280' },
    { name: 'Air Quality', value: 'Good', icon: '🍃', status: 'normal', color: '#10b981' },
    { name: 'Garage Door', value: 'Open', icon: '🚗', status: 'alert', color: '#ef4444' },
    { name: 'Kitchen Leak', value: 'Dry', icon: '💦', status: 'normal', color: '#10b981' },
    { name: 'Smoke Detector', value: 'Safe', icon: '🔥', status: 'normal', color: '#10b981' }
  ]);

  React.useEffect(() => {
    const interval = setInterval(() => {
      setSensors(prev => prev.map(s => {
        if (s.name === 'Living Room Temp') {
          const t = (70 + Math.random() * 5).toFixed(1);
          return { ...s, value: t + ' °F' };
        }
        if (s.name === 'Bedroom Humidity') {
          const h = Math.round(40 + Math.random() * 20);
          return { ...s, value: h + ' %', color: h > 60 ? '#f59e0b' : '#3b82f6' };
        }
        return s;
      }));
    }, 8000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', padding: 16, borderRadius: 8, boxSizing: 'border-box' }}>
      <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, color: '#9ca3af' }}>Sensor Dashboard</div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, height: 'calc(100% - 32px)', overflow: 'auto' }}>
        {sensors.map((s, i) => (
          <div key={i} style={{ background: '#1f2937', borderRadius: 8, padding: 12, display: 'flex', alignItems: 'center', gap: 10, borderLeft: '4px solid ' + s.color }}>
            <span style={{ fontSize: 22 }}>{s.icon}</span>
            <div style={{ minWidth: 0 }}>
              <div style={{ fontSize: 11, color: '#9ca3af', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{s.name}</div>
              <div style={{ fontSize: 16, fontWeight: 700, color: s.color }}>{s.value}</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<SensorDashboard/>);
